SELECT *
FROM game_results
WHERE total_winners = (
  SELECT MAX(total_winners)
  FROM game_results
);

SELECT AVG(prize_per_winner) 
FROM game_results 
WHERE game_id = 0;

SELECT game_id, total_winners 
FROM game_results
WHERE total_winners > 1;

SELECT COUNT(DISTINCT player_id) AS TotalWinningPlayers
FROM winnings
WHERE amount > 0;

SELECT *
FROM games
WHERE game_id IN (SELECT game_id FROM winnings);
